module piso_shift_register (
    input clk,
    input reset,
    input load,
    input [7:0] data_in,
    output reg data_out
);

    reg [7:0] obf_shift_reg;

    always @(posedge clk or posedge reset) begin
        if (reset)
            obf_shift_reg <= 8'b00000000;
        else if (load)
            obf_shift_reg <= data_in;
        else
            obf_shift_reg <= {obf_shift_reg[6:0], 1'b0};
    end

    always @(*) begin
        data_out = obf_shift_reg[7];
    end

endmodule
